{
  "shots": [
    {
      "shot_id": "SH08",
      "priority": "P0",
      "intent": "承接化妆品盒警告后的紧张，让美咲通过捏紧浅蓝丝巾和一句话揭示她对彩花计划的怨恨记忆。",
      "duration_sec": 5,
      "shot_type": "双人中近景",
      "movement": "固定机位",
      "framing_focus": "首帧稳定双人中近景：佐藤美咲蹲坐在客厅地板右侧，脸略低垂居中，双手在胸前下方捏紧 AYAKA_LIGHT_BLUE_SILK_SCARF_01；田中健一在左前景半侧身沉默，人物衣着完整，保持日常社交距离，朴素克制呈现。",
      "action_intent": "本镜头以美咲一句对白为主；她保持坐姿，手指在同一位置轻轻收紧丝巾，随后抬眼说话，健一全程沉默无口型。",
      "emotion_intent": "美咲的防备从低头和收紧手指中显露，台词带出她对姐姐彩花既依赖又怨恨的记忆。",
      "scene_id": "EP06_LIVING_ROOM_RELIC_CONFRONTATION",
      "scene_name": "客厅地板姐妹计划对质",
      "dialogue": [
        {
          "speaker": "佐藤美咲",
          "text": "彩花总说，要把小樱带进她的世界。像我当年。",
          "purpose": "揭示彩花想把小樱带进银座世界，也暴露美咲对当年经历的怨恨。",
          "source": "onscreen",
          "listener": "田中健一"
        }
      ],
      "narration": [],
      "subtitle": [
        "彩花总说，要把小樱带进她的世界。像我当年。"
      ],
      "positive_core": "首帧稳定双人中近景：佐藤美咲蹲坐在健一整理遗物的客厅地板右侧，脸略低垂居中，双手在胸前下方捏紧 AYAKA_LIGHT_BLUE_SILK_SCARF_01，田中健一在左前景半侧身沉默，人物衣着完整，保持日常社交距离，朴素克制呈现。客厅保持低饱和暖灰色夜间光线，地板近处有柔和阴影，镜头固定，美咲只用极小幅度抬眼和口型完成台词。",
      "first_frame_contract": {
        "location": "健一整理遗物的客厅",
        "visual_center": "佐藤美咲低垂的脸与她双手捏紧的浅蓝丝巾",
        "visible_characters": [
          "佐藤美咲",
          "田中健一"
        ],
        "character_positions": {
          "佐藤美咲": "画面右侧偏中心，蹲坐在地板旁，脸部为主要视觉中心",
          "田中健一": "画面左前景半侧身，只露出沉默侧脸和肩部"
        },
        "key_props": [
          "AYAKA_LIGHT_BLUE_SILK_SCARF_01"
        ],
        "speaking_state": "首帧美咲低头准备开口，随后佐藤美咲为唯一画面内说话人；田中健一全程沉默无口型；无电话远端声音",
        "camera_motion_allowed": "固定机位"
      },
      "dialogue_blocking": {
        "active_speaker": "佐藤美咲",
        "first_speaker": "佐藤美咲",
        "speaker_visual_priority": "center_face",
        "silent_visible_characters": [
          "田中健一"
        ],
        "lip_sync_policy": "single_active_speaker"
      },
      "i2v_contract": {
        "shot_task": "dialogue",
        "risk_level": "low",
        "risk_notes": "双人可见但仅美咲一个画面内说话人；健一保持沉默无口型；道具运动限制为手指轻微收紧丝巾。",
        "prop_library": {
          "AYAKA_LIGHT_BLUE_SILK_SCARF_01": {
            "display_name": "浅蓝丝巾",
            "count": "1条",
            "size": "约150厘米 × 35厘米",
            "color": "浅蓝色，低饱和冷调",
            "material": "丝质，表面有柔和反光",
            "structure": "长方形薄丝巾，边缘有细窄卷边",
            "canonical_motion_policy": "默认折叠或半铺在健一膝前；只允许由健一或美咲手部触碰、捏紧、放下或滑落。"
          }
        },
        "prop_contract": [
          {
            "prop_id": "AYAKA_LIGHT_BLUE_SILK_SCARF_01",
            "position": "首帧位于美咲双手之间，处在她胸前下方和画面下中部，丝巾两端向她膝前自然垂落",
            "first_frame_visible": true,
            "motion_policy": "本镜头只允许美咲手指在同一位置轻微收紧，使丝面出现细小褶痕；不发生交接、不离开画面中心下方",
            "controlled_by": "佐藤美咲"
          }
        ],
        "phone_contract": {
          "holder": "none",
          "screen_orientation": "not_applicable",
          "screen_content_visible": false
        }
      },
      "source_basis": "对应 TARGET_FACTS 14：“她低头整理丝巾，手指收紧布料。‘彩花总说，要把小樱带进她的世界。像我当年。’”"
    }
  ],
  "qa_report": [
    {
      "check": "only target shot",
      "result": "pass",
      "notes": "shots 数组长度为 1，且唯一镜头为 SH08，时长 5 秒。"
    },
    {
      "check": "I2V single speaker",
      "result": "pass",
      "notes": "本镜头只有佐藤美咲一个画面内主动说话人，田中健一可见但沉默无口型。"
    },
    {
      "check": "first frame stability",
      "result": "pass",
      "notes": "framing_focus 与 positive_core 第一元素均为单一地点、单一时间的稳定首帧。"
    },
    {
      "check": "prop consistency",
      "result": "pass",
      "notes": "浅蓝丝巾使用 prop_id AYAKA_LIGHT_BLUE_SILK_SCARF_01，并沿用指定数量、尺寸、颜色、材质、结构与运动策略。"
    },
    {
      "check": "story traceability",
      "result": "pass",
      "notes": "镜头内容直接对应 TARGET_FACTS 14 与 TARGET_SPINE_ROW：美咲捏紧丝巾并说出彩花想把小樱带进她的世界。"
    }
  ]
}
